import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Article } from '../../../../includes';
import { agroAdminRouteNames } from '../../../routeNames';


const style = theme => ({
    root: {
    }
})
class _BlogView extends Component {
    constructor(props) {
        super(props);
        this.blog = this.props.location.state;
    }
    
    render() {
        const {classes} = this.props;
        return (
            <div className={classes.root}>
                <Article {...this.blog} 
                    editable
                    editLink={{pathname : agroAdminRouteNames.blogEdit_+this.blog._id, state : this.blog}}/>
            </div>
        );
    }
}


_BlogView.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = state => ({
    state
})


export const BlogView = connect(mapStateToProps)(withStyles(style)(_BlogView));
export {BlogView as default}